#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <time.h>
#include <stdint.h>
#include <stdbool.h>

#define MAX 10001

int maxNOSS(int* arr, int n) {
    int maxNOSS = 0;
    for (int mask = 0; mask < (1 << n); mask++) {
        int sum = 0;
        for (int i = 0; i < n; i++) {
            if ((mask & (1 << i)) != 0) {
                sum += arr[i];
            }
        }
        maxNOSS = (sum > maxNOSS) ? sum : maxNOSS;
    }
    return maxNOSS + 1;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        int* arr = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
        }
        int maxNOSS = maxNOSS(arr, n);
        printf("%d\n", maxNOSS);
        free(arr);
    }
    return 0;
}

